use actix_web::{web, App, HttpServer};
use actix_files as fs;

// Handler function to serve files from the 'uploads' directory.
// It takes the filename as a path parameter.
async fn serve_upload(path: web::Path<String>) -> actix_web::Result<fs::NamedFile> {
    let filename = path.into_inner();
    // Construct the full path to the file within the 'uploads' directory.
    // The "./uploads/" prefix makes it relative to the directory where the application is run.
    let file_path = format!("./uploads/{}", filename);

    // Use NamedFile::open to asynchronously open and serve the file.
    // This function handles several important aspects:
    // - Asynchronous file reading.
    // - Setting appropriate Content-Type headers based on the file's extension
    //   (e.g., text/plain for .txt, image/jpeg for .jpg, application/pdf for .pdf).
    // - Handling "file not found" errors by returning a 404 response.
    // - Provides basic security against simple path traversal attacks
    //   by canonicalizing the path and ensuring it stays within the intended root.
    fs::NamedFile::open(file_path).map_err(actix_web::Error::from)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // --- For demonstration purposes: create 'uploads' directory and some dummy files ---
    // In a real production application, the 'uploads' directory would typically be
    // pre-existing and managed separately. This ensures the example is runnable out-of-the-box.
    let uploads_dir = "./uploads";
    std::fs::create_dir_all(uploads_dir)?; // Create the directory if it doesn't exist

    // Create a dummy text file
    std::fs::write(format!("{}/hello.txt", uploads_dir), "Hello from the text file!")?;
    // Create a dummy JSON file
    std::fs::write(format!("{}/data.json", uploads_dir), r#"{ "name": "Rust", "version": "1.0" }"#)?;
    // Create a dummy PDF file (content is not actual PDF, but good for testing MIME type detection)
    std::fs::write(format!("{}/document.pdf", uploads_dir), "%PDF-1.4\n1 0 obj <</Type/Catalog>> endobj")?;
    // --- End demonstration setup ---

    HttpServer::new(|| {
        App::new()
            .service(
                // Define the route to catch any filename after /uploads/
                // The `{filename:.+}` segment captures the rest of the path (including dots)
                // as the 'filename' parameter, allowing files like 'my_document.pdf'.
                web::resource("/uploads/{filename:.+}")
                    .to(serve_upload)
            )
    })
    .bind(("127.0.0.1", 8080))? // Bind the server to localhost:8080
    .run()                     // Run the Actix-web server
    .await
}